code = """import pandas as pd
import json

# The previous state result is a dictionary, no need to json.loads it.
state = locals()['var_function-call-1711969212963759136']
symbols = state['symbols']
company_day_counts = state['company_day_counts']
current_symbol_index = state['current_symbol_index']

# Process data for the symbol just queried (ALACU), which is at current_symbol_index - 1
previous_symbol = symbols[current_symbol_index - 1]

# Load the stock data for the previously queried symbol (ALACU)
with open(locals()['var_function-call-2574141024642243972'], 'r') as f:
    stock_data_for_previous_symbol = json.load(f)

df = pd.DataFrame(stock_data_for_previous_symbol)
df['Low'] = pd.to_numeric(df['Low'])
df['High'] = pd.to_numeric(df['High'])

# Calculate the number of days where (High - Low) > 0.20 * Low for ALACU
days_exceeding_threshold = df[((df['High'] - df['Low']) > (0.20 * df['Low']))].shape[0]
company_day_counts[previous_symbol] = days_exceeding_threshold

# Now, prepare for the next symbol in the list
if current_symbol_index < len(symbols):
    current_symbol = symbols[current_symbol_index] # This is AMHC
    # Construct the SQL query for the current symbol (AMHC) for 2019 data.
    # DuckDB requires double quotes for table names, and single quotes for string literals in LIKE clause.
    sql_query = f"SELECT Date, Low, High FROM \"{current_symbol}\" WHERE Date LIKE '2019-%%';"

    next_action = {
        "action": "query_db",
        "db_name": "stocktrade_database",
        "query": sql_query,
        "current_symbol": current_symbol,
        "state": { # Pass the entire updated state to the next step
            "symbols": symbols,
            "company_day_counts": company_day_counts,
            "current_symbol_index": current_symbol_index + 1 # Increment for the next iteration
        }
    }
else:
    # All symbols processed, now calculate final result
    next_action = {
        "action": "calculate_final_result",
        "state": {
            "symbols": symbols,
            "company_day_counts": company_day_counts,
            "current_symbol_index": current_symbol_index
        }
    }

print("__RESULT__:")
print(json.dumps(next_action))"""

